import android.content.ContentValues;
import android.content.Context;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;
import android.util.Log;
import java.util.List;

public class NoteDatabaseHelper extends SQLiteOpenHelper {
 private static final String TAG = "NoteDB";
 private static final String DATABASE_NAME = "notes.db";
 private static final int DATABASE_VERSION = 1;

 public NoteDatabaseHelper(Context context) {
 super(context, DATABASE_NAME, null, DATABASE_VERSION);
 }

 @Override
 public void onCreate(SQLiteDatabase db) {
 // Create notes table
 db.execSQL("CREATE TABLE notes (" +
 "_id INTEGER PRIMARY KEY AUTOINCREMENT, " +
 "title TEXT NOT NULL, " +
 "body TEXT, " +
 "created_at INTEGER DEFAULT (strftime('%s', 'now'))" +
 ")");

 // Create note_tags table
 db.execSQL("CREATE TABLE note_tags (" +
 "_id INTEGER PRIMARY KEY AUTOINCREMENT, " +
 "note_id INTEGER NOT NULL, " +
 "tag_name TEXT NOT NULL, " +
 "FOREIGN KEY(note_id) REFERENCES notes(_id)" +
 ")");
 }

 /**
 * Inserts a note with its tags in a single transaction.
 * Either both the note and all tags are inserted, or none are.
 */
 public boolean insertNoteWithTags(String title, String body, List<String> tags) {
 // Get writable database instance
 SQLiteDatabase db = getWritableDatabase();
 boolean success = false;

 // Begin the transaction - acquires database lock
 db.beginTransaction();

 try {
 // Step 1: Insert the note itself
 ContentValues noteValues = new ContentValues();
 noteValues.put("title", title);
 noteValues.put("body", body);

 long noteId = db.insert("notes", null, noteValues);

 // Check if note insertion failed
 if (noteId == -1) {
 throw new SQLException("Failed to insert note");
 }

 // Step 2: Insert each tag linked to this note
 for (String tag : tags) {
 ContentValues tagValues = new ContentValues();
 tagValues.put("note_id", noteId);
 tagValues.put("tag_name", tag);

 long tagId = db.insert("note_tags", null, tagValues);

 if (tagId == -1) {
 throw new SQLException("Failed to insert tag: " + tag);
 }
 }

 // Step 3: Mark transaction as successful - this commits on endTransaction()
 db.setTransactionSuccessful();
 success = true;

 Log.d(TAG, "Note with tags inserted successfully");

 } catch (SQLException e) {
 // Transaction will be automatically rolled back
 Log.e(TAG, "Transaction failed: " + e.getMessage());
 success = false;

 } finally {
 // Step 4: Always end transaction - commits if setTransactionSuccessful() was called
 // Otherwise rolls back all changes
 db.endTransaction();
 }

 return success;
 }

 /**
 * Demonstrates batch insert for performance improvement.
 * Using transactions for bulk inserts is ~25x faster.
 */
 public void bulkInsertContacts(List<Contact> contacts) {
 SQLiteDatabase db = getWritableDatabase();

 db.beginTransaction();
 try {
 for (Contact contact : contacts) {
 ContentValues values = new ContentValues();
 values.put("name", contact.getName());
 values.put("phone", contact.getPhone());
 values.put("email", contact.getEmail());

 db.insert("contacts", null, values);
 // Each insert is fast because they're buffered in transaction
 }

 // Commit all inserts at once
 db.setTransactionSuccessful();
 Log.d(TAG, "Bulk insert completed: " + contacts.size() + " contacts");

 } finally {
 db.endTransaction();
 }
 }

 /**
 * Bank transfer example - demonstrates atomicity requirement.
 * Both debit and credit must succeed together.
 */
 public boolean transferAmount(int fromId, int toId, double amount) {
 SQLiteDatabase db = getWritableDatabase();

 db.beginTransaction();
 try {
 // Debit from source account
 db.execSQL("UPDATE accounts SET balance = balance - ? WHERE _id = ?",
 new Object[]{amount, fromId});

 // Credit to destination account
 db.execSQL("UPDATE accounts SET balance = balance + ? WHERE _id = ?",
 new Object[]{amount, toId});

 // Log the transfer for audit trail
 ContentValues logValues = new ContentValues();
 logValues.put("from_account", fromId);
 logValues.put("to_account", toId);
 logValues.put("amount", amount);
 logValues.put("timestamp", System.currentTimeMillis());
 db.insert("transfer_log", null, logValues);

 // Mark successful - commit all changes atomically
 db.setTransactionSuccessful();
 return true;

 } catch (Exception e) {
 Log.e(TAG, "Transfer failed: " + e.getMessage());
 return false;

 } finally {
 db.endTransaction();
 }
 }

 @Override
 public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
 // Handle database upgrades
 }
}

