#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sqlite3.h>

#define DATABASE_NAME "bank.db"

// Callback function for query results
int callback(void *NotUsed, int argc, char **argv, char **azColName) {
 for (int i = 0; i < argc; i++) {
 printf("%s = %s\n", azColName[i], argv[i] ? argv[i] : "NULL");
 }
 printf("\n");
 return 0;
}

// Error handler macro
#define CHECK_ERROR(db, rc, msg) \
 if (rc != SQLITE_OK) { \
 fprintf(stderr, "SQL Error: %s\n", msg); \
 sqlite3_errmsg(db); \
 if (db) sqlite3_close(db); \
 return rc; \
 }

/**
 * Creates the accounts table for banking example
 */
int createTables(sqlite3 *db) {
 char *errMsg = NULL;
 int rc;

 const char *sql = "CREATE TABLE IF NOT EXISTS accounts ("
 "id INTEGER PRIMARY KEY,"
 "name TEXT NOT NULL,"
 "balance REAL DEFAULT 0.0"
 ");"
 "CREATE TABLE IF NOT EXISTS transfers ("
 "id INTEGER PRIMARY KEY AUTOINCREMENT,"
 "from_account INTEGER,"
 "to_account INTEGER,"
 "amount REAL,"
 "timestamp DATETIME DEFAULT CURRENT_TIMESTAMP"
 ");";

 rc = sqlite3_exec(db, sql, NULL, 0, &errMsg);
 if (rc != SQLITE_OK) {
 fprintf(stderr, "SQL error: %s\n", errMsg);
 sqlite3_free(errMsg);
 return rc;
 }

 return SQLITE_OK;
}

/**
 * Performs atomic money transfer between accounts using transactions.
 * Either both debit and credit succeed, or neither does.
 */
int transferFunds(sqlite3 *db, int fromId, int toId, double amount) {
 sqlite3_stmt *stmt;
 int rc;
 char sql[256];

 // Begin transaction - acquires EXCLUSIVE lock
 rc = sqlite3_exec(db, "BEGIN TRANSACTION", NULL, NULL, NULL);
 CHECK_ERROR(db, rc, "Failed to begin transaction");

 printf("Transaction started...\n");

 // Step 1: Debit from source account
 snprintf(sql, sizeof(sql), 
 "UPDATE accounts SET balance = balance - ? WHERE id = ?");
 rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
 CHECK_ERROR(db, rc, "Failed to prepare debit statement");

 sqlite3_bind_double(stmt, 1, amount);
 sqlite3_bind_int(stmt, 2, fromId);

 rc = sqlite3_step(stmt);
 if (rc != SQLITE_DONE) {
 fprintf(stderr, "Debit failed\n");
 sqlite3_finalize(stmt);
 sqlite3_exec(db, "ROLLBACK", NULL, NULL, NULL);
 return rc;
 }
 sqlite3_finalize(stmt);

 // Step 2: Credit to destination account
 snprintf(sql, sizeof(sql), 
 "UPDATE accounts SET balance = balance + ? WHERE id = ?");
 rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
 CHECK_ERROR(db, rc, "Failed to prepare credit statement");

 sqlite3_bind_double(stmt, 1, amount);
 sqlite3_bind_int(stmt, 2, toId);

 rc = sqlite3_step(stmt);
 if (rc != SQLITE_DONE) {
 fprintf(stderr, "Credit failed\n");
 sqlite3_finalize(stmt);
 sqlite3_exec(db, "ROLLBACK", NULL, NULL, NULL);
 return rc;
 }
 sqlite3_finalize(stmt);

 // Step 3: Log the transfer
 snprintf(sql, sizeof(sql), 
 "INSERT INTO transfers (from_account, to_account, amount) VALUES (?, ?, ?)");
 rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
 CHECK_ERROR(db, rc, "Failed to prepare log statement");

 sqlite3_bind_int(stmt, 1, fromId);
 sqlite3_bind_int(stmt, 2, toId);
 sqlite3_bind_double(stmt, 3, amount);

 rc = sqlite3_step(stmt);
 sqlite3_finalize(stmt);

 if (rc != SQLITE_DONE) {
 fprintf(stderr, "Transfer log failed\n");
 sqlite3_exec(db, "ROLLBACK", NULL, NULL, NULL);
 return rc;
 }

 // Step 4: Commit the transaction
 rc = sqlite3_exec(db, "COMMIT", NULL, NULL, NULL);
 CHECK_ERROR(db, rc, "Failed to commit transaction");

 printf("Transaction committed successfully! Transferred %.2f from account %d to %d\n",
 amount, fromId, toId);

 return SQLITE_OK;
}

/**
 * Demonstrates bulk insert performance with transactions
 */
int bulkInsertRecords(sqlite3 *db, int count) {
 sqlite3_stmt *stmt;
 int rc;

 // Begin transaction for batch insert
 rc = sqlite3_exec(db, "BEGIN TRANSACTION", NULL, NULL, NULL);
 CHECK_ERROR(db, rc, "Failed to begin transaction");

 printf("Inserting %d records in a transaction...\n", count);

 const char *sql = "INSERT INTO accounts (name, balance) VALUES (?, ?)";
 rc = sqlite3_prepare_v2(db, sql, -1, &stmt, NULL);
 CHECK_ERROR(db, rc, "Failed to prepare insert");

 // Insert multiple records in single transaction
 for (int i = 1; i <= count; i++) {
 char name[50];
 snprintf(name, sizeof(name), "Account_%d", i);

 sqlite3_bind_text(stmt, 1, name, -1, SQLITE_TRANSIENT);
 sqlite3_bind_double(stmt, 2, (double)(i * 100));

 rc = sqlite3_step(stmt);
 if (rc != SQLITE_DONE) {
 fprintf(stderr, "Insert failed at record %d\n", i);
 sqlite3_finalize(stmt);
 sqlite3_exec(db, "ROLLBACK", NULL, NULL, NULL);
 return rc;
 }

 // Reset statement for next iteration
 sqlite3_reset(stmt);
 }

 sqlite3_finalize(stmt);

 // Commit all inserts at once
 rc = sqlite3_exec(db, "COMMIT", NULL, NULL, NULL);
 CHECK_ERROR(db, rc, "Failed to commit bulk insert");

 printf("Successfully inserted %d records\n", count);

 return SQLITE_OK;
}

int main(int argc, char **argv) {
 sqlite3 *db;
 int rc;

 // Open database connection
 rc = sqlite3_open(DATABASE_NAME, &db);
 if (rc) {
 fprintf(stderr, "Can't open database: %s\n", sqlite3_errmsg(db));
 return 1;
 }

 printf("Database opened successfully\n");

 // Create tables
 rc = createTables(db);
 if (rc != SQLITE_OK) {
 sqlite3_close(db);
 return 1;
 }

 // Insert initial test data (without transaction - single insert)
 sqlite3_exec(db, "INSERT OR IGNORE INTO accounts (id, name, balance) VALUES (1, 'Alice', 1000.0)", NULL, NULL, NULL);
 sqlite3_exec(db, "INSERT OR IGNORE INTO accounts (id, name, balance) VALUES (2, 'Bob', 500.0)", NULL, NULL, NULL);

 // Perform atomic transfer
 printf("\n--- Performing Transfer ---\n");
 rc = transferFunds(db, 1, 2, 250.0);

 if (rc == SQLITE_OK) {
 printf("Transfer completed!\n");
 } else {
 printf("Transfer failed and rolled back!\n");
 }

 // Show account balances
 printf("\n--- Account Balances ---\n");
 sqlite3_exec(db, "SELECT id, name, balance FROM accounts", callback, NULL, NULL);

 // Demonstrate bulk insert performance
 printf("\n--- Bulk Insert Demo ---\n");
 bulkInsertRecords(db, 1000);

 // Close database
 sqlite3_close(db);
 printf("\nDatabase closed\n");

 return 0;
}
